import{_ as s,o as e,c as n,af as p}from"./chunks/framework.Bv7UzdO-.js";const u=JSON.parse('{"title":"存储引擎","description":"","frontmatter":{},"headers":[],"relativePath":"posts/architecture/storage-engine.md","filePath":"posts/architecture/storage-engine.md","lastUpdated":1776948123000}'),t={name:"posts/architecture/storage-engine.md"};function l(i,a,o,c,d,r){return e(),n("div",null,[...a[0]||(a[0]=[p(`<h1 id="存储引擎" tabindex="-1">存储引擎 <a class="header-anchor" href="#存储引擎" aria-label="Permalink to &quot;存储引擎&quot;">​</a></h1><p>底层存储引擎是一个追加写入式（append-only）分段日志。</p><h2 id="数据写入流程" tabindex="-1">数据写入流程 <a class="header-anchor" href="#数据写入流程" aria-label="Permalink to &quot;数据写入流程&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Set(key, value)</span></span>
<span class="line"><span>  1. 构造 Record: Magic(2) + Op(1) + KeyLen(4) + ValLen(4) + Key + Value + CRC32(4)</span></span>
<span class="line"><span>  2. 写入当前活跃段文件</span></span>
<span class="line"><span>  3. Flush + Sync (fsync)</span></span>
<span class="line"><span>  4. 更新内存 HashMap (values[key] = value)</span></span>
<span class="line"><span>  5. 更新 Index (key → segmentID + offset)</span></span>
<span class="line"><span>  6. 更新 Bloom Filter</span></span>
<span class="line"><span>  7. 如果段文件 &gt;= 16MB，轮转到新段</span></span></code></pre></div><h2 id="数据读取流程" tabindex="-1">数据读取流程 <a class="header-anchor" href="#数据读取流程" aria-label="Permalink to &quot;数据读取流程&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Get(key)</span></span>
<span class="line"><span>  1. 查内存 HashMap (values)</span></span>
<span class="line"><span>  2. 命中 → 返回值副本</span></span>
<span class="line"><span>  3. 未命中 → 查 Bloom Filter</span></span>
<span class="line"><span>  4. Bloom 说不存在 → 返回 ErrNotFound</span></span></code></pre></div><p>读取是纯内存操作，不涉及磁盘 I/O。</p><h2 id="二进制记录格式" tabindex="-1">二进制记录格式 <a class="header-anchor" href="#二进制记录格式" aria-label="Permalink to &quot;二进制记录格式&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌───────┬──────┬────────┬────────┬─────┬───────┬───────┐</span></span>
<span class="line"><span>│ Magic │  Op  │ KeyLen │ ValLen │ Key │ Value │ CRC32 │</span></span>
<span class="line"><span>│ 2B    │ 1B   │ 4B     │ 4B     │ ... │ ...   │ 4B    │</span></span>
<span class="line"><span>└───────┴──────┴────────┴────────┴─────┴───────┴───────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Magic = 0xF0F1</span></span>
<span class="line"><span>Op    = 1 (Set) | 2 (Delete)</span></span></code></pre></div><h2 id="段文件管理" tabindex="-1">段文件管理 <a class="header-anchor" href="#段文件管理" aria-label="Permalink to &quot;段文件管理&quot;">​</a></h2><ul><li>文件命名：<code>segment-{N}.dat</code>（N 从 0 递增）</li><li>每个段最大 16MB，满了自动轮转到新段</li><li>压缩（Compact）：删除所有段文件，将所有活跃键重写到新的 <code>segment-0</code></li></ul><h2 id="删除机制" tabindex="-1">删除机制 <a class="header-anchor" href="#删除机制" aria-label="Permalink to &quot;删除机制&quot;">​</a></h2><p>删除操作写入一条 <code>Op=Delete</code> 记录，并从内存 HashMap 和索引中移除。已删除的数据在压缩时被清理。</p><h2 id="索引快照" tabindex="-1">索引快照 <a class="header-anchor" href="#索引快照" aria-label="Permalink to &quot;索引快照&quot;">​</a></h2><p>启动时优先加载 <code>index.snapshot</code> 文件，然后回放段文件。快照格式：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Magic(8B &quot;KVINDEX1&quot;) + EntryCount(4B) + [KeyLen(4B) + Key + SegmentID(8B) + Offset(8B)]...</span></span></code></pre></div>`,16)])])}const g=s(t,[["render",l]]);export{u as __pageData,g as default};
